std::filesystem::path get_exe_dir();

auto get_file_path(std::string client_message) {
  auto const start = client_message.find_first_of("/") + 1;
  auto const end = client_message.find("HTTP/1.1") - 1;
  std::filesystem::path const path = client_message.substr(start, end - start);
  return get_exe_dir().concat(path.string());
}

auto read_file_to_string(std::filesystem::path path) {
  std::ifstream file(path, std::ios::in | std::ios::binary);
  if (!file.is_open()) {
    std::string nothing{""};
    return nothing;
  };
  std::string const content{std::istreambuf_iterator<char>(file),
                            std::istreambuf_iterator<char>()};
  file.close();
  return content;
}

const std::string tab_reloader = "<script>onload = () => setTimeout(() => "
                                 "onfocus = () => location.reload());</script>";

bool has_tab_reloader(std::filesystem::path path) {
  return read_file_to_string(path).find(tab_reloader) < std::string::npos;
}

void inject_tab_reloader() {
  for (const auto &file :
       std::filesystem::recursive_directory_iterator(get_exe_dir())) {
    const auto path = file.path();
    if (path.extension() == ".html") {
      if (has_tab_reloader(path)) {
        continue;
      }
      std::ofstream file(path, std::ios::app);
      if (!file.is_open()) {
        continue;
      }
      file << tab_reloader << "\n";
      file.close();
    }
  }
}

auto get_entry_point() {
  for (const auto &file : std::filesystem::directory_iterator(get_exe_dir())) {
    if (file.path().extension() == ".html") {
      return file.path().filename();
    }
  }
  return std::filesystem::path{};
}

int main() {
  int WEBSCALE_FACTOR = std::thread::hardware_concurrency();

  Socket socket{"127.0.0.1", 8080, WEBSCALE_FACTOR};

  inject_tab_reloader();

  std::cout << "Listening on: \x1B[36m127.0.0.1:8080\033[0m\t\t" << std::endl;
  std::cout << "Entry: \x1B[36mhttp://localhost:8080/"
            << get_entry_point().string() << "\033[0m\t\t" << std::endl;

  socket.listenOnPort(std::move([](std::string message) {
    auto path = get_file_path(message);
