#include <arpa/inet.h>
#include <functional>
#include <iostream>
#include <netinet/in.h>
#include <string>
#include <sys/socket.h>
#include <unistd.h>

class Socket {
private:
  int server_sock;
  int sock_status = 0;
  ThreadPool threadPool;

public:
  Socket(const std::string IP, const int PORT, const int WEBSCALE_FACTOR,
         const int BACKLOG = 128)
      : threadPool{WEBSCALE_FACTOR} {
    server_sock = socket(AF_INET, SOCK_STREAM, IPPROTO_TCP);
    if (errors(server_sock)) {
      sock_status = -1;
    }
    sockaddr_in server_addr{};
    server_addr.sin_family = AF_INET;
    server_addr.sin_port = htons(PORT);
    inet_pton(AF_INET, IP.c_str(), &(server_addr.sin_addr));
    constexpr socklen_t server_len = sizeof server_addr;
    constexpr int optval = 1;
    int res =
        setsockopt(server_sock, SOL_SOCKET, SO_REUSEPORT, &optval, sizeof(int));
    if (errors(res)) {
      sock_status = -1;
    }
    res = bind(server_sock, (struct sockaddr *)&server_addr, server_len);
    if (errors(res)) {
      sock_status = -1;
    }
    res = listen(server_sock, BACKLOG);
    if (errors(res)) {
      sock_status = -1;
    }
    if (sock_status == -1) {
      close(server_sock);
    } else {
      sock_status = 1;
    }
  }

  ~Socket() {
    close(server_sock);
    threadPool.kill();
  }

  void listenOnPort(std::function<std::string(std::string)> callback) {
    if (sock_status == -1) {
      errors(server_sock);
      return;
    }
    while (true) {
      const sockaddr_in client_addr{};
      socklen_t client_len = sizeof client_addr;
      const int client_sock =
          accept(server_sock, (struct sockaddr *)&client_addr, &client_len);
      if (errors(client_sock)) {
        close(client_sock);
        continue;
      }
      threadPool << std::move([client_sock, callback]() {
        std::string client_msg;
        client_msg.resize(4096);
        const int res =
            recv(client_sock, client_msg.data(), client_msg.size(), 0);
        if (errors(res)) {
          close(client_sock);
          return;
        }
        std::string response;
        try {
          response = callback(client_msg);
        } catch (const std::exception &error) {
          std::cerr << error.what();
        }
        send(client_sock, response.data(), response.size(), 0);
        close(client_sock);
      });
    }
  }

private:
  static bool errors(int sd) {
    if (sd >= 0) {
      return false;
    }
    std::cerr << "\x1B[31mSocket has broke \033[0m\t\t";
    std::cerr << sd << std::endl;
    return true;
  }
};

