#include <deque>
#include <functional>
#include <iostream>
#include <pthread.h>
#include <vector>

class ThreadPool {
  struct WorkQueue {
    std::deque<std::function<void()>> call_stack;
    pthread_mutex_t mutex = PTHREAD_MUTEX_INITIALIZER;
    pthread_cond_t request = PTHREAD_COND_INITIALIZER;
    pthread_cond_t response = PTHREAD_COND_INITIALIZER;
    std::atomic<bool> stop{false};
  };

  WorkQueue workQueue;
  std::vector<pthread_t> threads;
  constexpr static int CALLSTACK_SIZE{3000};

  static void *worker_thread(void *data) {
    auto &workQueue = *(static_cast<WorkQueue *>(data));
    while (!workQueue.stop) {
      pthread_mutex_lock(&workQueue.mutex);
      while (workQueue.call_stack.empty()) {
        const int rc = pthread_cond_wait(&workQueue.request, &workQueue.mutex);
        if (rc != 0 && workQueue.stop) {
          break;
        }
      }
      const auto callback = std::move(workQueue.call_stack.front());
      workQueue.call_stack.pop_front();
      pthread_cond_signal(&workQueue.response);
      pthread_mutex_unlock(&workQueue.mutex);
      try {
        callback();
      } catch (const std::exception &error) {
        std::cerr << error.what();
      }
    }
    return EXIT_SUCCESS;
  }

public:
  ThreadPool(int num_threads) {
    while (--num_threads >= 0) {
      pthread_t p_thread;
      const int tid = pthread_create(&p_thread, NULL, worker_thread,
                                     static_cast<void *>(&workQueue));
      if (tid != 0) {
        std::cerr << "Failed to create thread errno: " << tid << std::endl;
        continue;
      }
      threads.push_back(p_thread);
    }
    pthread_mutex_lock(&workQueue.mutex);
    pthread_cond_broadcast(&workQueue.request);
    pthread_mutex_unlock(&workQueue.mutex);
  }

  ThreadPool &operator<<(std::function<void()> callback) {
    pthread_mutex_lock(&workQueue.mutex);
    while (workQueue.call_stack.size() > CALLSTACK_SIZE) {
      pthread_cond_wait(&workQueue.response, &workQueue.mutex);
    }
    workQueue.call_stack.emplace_front(std::move(callback));
    pthread_cond_signal(&workQueue.request);
    pthread_mutex_unlock(&workQueue.mutex);
    return *this;
  }

  void kill() {
    pthread_mutex_lock(&workQueue.mutex);
    workQueue.stop.store(true);
    pthread_cond_broadcast(&workQueue.request);
    pthread_mutex_unlock(&workQueue.mutex);
    for (pthread_t t : threads) {
      pthread_join(t, nullptr);
    }
    pthread_mutex_destroy(&workQueue.mutex);
    pthread_cond_destroy(&workQueue.response);
    pthread_cond_destroy(&workQueue.request);
  }

  ~ThreadPool() { 
    kill(); 
  };
};
